mapper.select:
SELECT
FROM tb_evt_event a LEFT JOIN tb_mbm_admin_user b ON a.create_id = b.id
ORDER BY order_no LIMIT #{offset}, #{recordSize}

mapper.insert:
INSERT INTO tb_evt_event (event_category, event_mng_sp, title, content
						, event_thumbnail
						, event_image
						, manager, start_date, end_date
						, event_notice_sp, event_notice_image ,event_notice_content
						, use_yn,  create_id, modified_date
)VALUES(	
		 #{eventCategory}
		,#{eventMngSp}
		,#{title}
		,#{content}				
		,#{eventThumbnail}
		,#{eventImage}				
		,#{manager}
		,#{startDate}
		,#{endDate}				
		,#{eventNoticeSp}
		,#{eventNoticeImage}
		,#{eventNoticeContent}				
		,#{useYn}
		,#{createId}
		,NULL
);

mapper.update:
UPDATE tb_evt_event 
SET		 title           =#{title}

		,event_category  =#{eventCategory}
		,event_mng_sp    =#{eventMngSp}

		,start_date      =#{startDate}
		,end_date        =#{endDate}

		,event_thumbnail =#{eventThumbnail}
		,event_image     =#{eventImage}

		,content         =#{content}
		,manager         =#{manager}


		,event_notice_sp = #{eventNoticeSp}
		,event_notice_image = #{eventNoticeImage}
		,event_notice_content = #{eventNoticeContent}


		,modified_date	=now()
		,modified_id	=#{modifiedId}
WHERE id = #{id}


UPDATE tb_evt_event 
SET		 use_yn			=#{useYn}
WHERE id = #{id}
